findings.recommendation:
Add a test that patches subprocess.run to raise an exception on the 'show rule name=all' call, then calls remove_firewall_rules() and asserts the fixed-list fallback is used. Do NOT mock _list_firewall_rules_by_prefix itself in this test — let the real function handle the exception:

  @patch('src.system_config.sys.platform', 'win32')
  @patch('src.system_config.subprocess.run')
  def test_remove_by_prefix_fallback_on_subprocess_exception(self, mock_run):
      import subprocess as sp
      mock_run.side_effect = sp.TimeoutExpired(['netsh'], 30)
      remove_firewall_rules()  # must not raise
      assert mock_run.call_count == len(BROWSER_EXES) * len(STUN_PORTS)
      expected_name = f'{FW_RULE_PREFIX}-chrome-udp-3478'
      mock_run.assert_any_call(
          ['netsh', 'advfirewall', 'firewall', 'delete', 'rule', f'name={expected_name}'],
          capture_output=True, text=True, timeout=10,
      )
